const input = $input.first().json;
const body = input.body || input;
const rawUrl = String(body.url || '').trim();
const requestedLang = String(body.lang || 'my').trim().toLowerCase();
const rawToken = String(body.token || '').trim();
const rawJobId = String(body.job_id || body.jobId || body.chatId || Date.now()).trim();

const voiceMap = {
  my: { voice: 'my-MM-ThihaNeural', name: 'Burmese' },
  en: { voice: 'en-US-ChristopherNeural', name: 'English' },
  ja: { voice: 'ja-JP-KeitaNeural', name: 'Japanese' },
  ko: { voice: 'ko-KR-InJoonNeural', name: 'Korean' },
};

const safeJobId = (rawJobId.replace(/[^A-Za-z0-9_-]/g, '').slice(0, 64) || String(Date.now()));
const userToken = rawToken.replace(/[\r\n\0]/g, '').slice(0, 1024);
const lang = Object.prototype.hasOwnProperty.call(voiceMap, requestedLang) ? requestedLang : 'my';
const voice = voiceMap[lang];

const urlMatch = rawUrl.match(/^(https?:\/\/(?:www\.)?(?:youtube\.com|youtu\.be|(?:www\.)?tiktok\.com|vm\.tiktok\.com|vt\.tiktok\.com|(?:www\.)?xiaohongshu\.com|xhslink\.com)\/[^\s]+)$/i);
if (!urlMatch) {
  return [{ json: { valid: false, error: 'Invalid URL. Supported: YouTube, TikTok, Xiaohongshu' } }];
}

const url = urlMatch[1];
let platform = 'unknown';
if (/youtube\.com|youtu\.be/i.test(url)) platform = 'youtube';
else if (/tiktok\.com/i.test(url)) platform = 'tiktok';
else if (/xiaohongshu\.com|xhslink\.com/i.test(url)) platform = 'xiaohongshu';

return [{
  json: {
    valid: true,
    url,
    source_url: url,
    platform,
    userToken,
    token_present: !!userToken,
    job_id: safeJobId,
    chatId: safeJobId,
    work_dir: '/media/dub/' + safeJobId,
    lang,
    lang_name: voice.name,
    vo_voice: voice.voice,
    vo_rate: '+18%',
    vo_pitch: '+0Hz',
    updated_at: new Date().toISOString()
  }
}];

const stdout = $input.first().json.stdout || '';
const config = $('Validate URL').first().json;

if (
  stdout.includes('ERROR: source.mp4 not found') ||
  stdout.includes('Sign in to confirm you') ||
  stdout.includes('HTTP Error 403') ||
  (!stdout.includes('RESOLUTION=') && !stdout.includes('source.mp4'))
) {
  const errLines = stdout.split('\n').filter((line) => line.includes('ERROR')).join(' | ');
  throw new Error('Download failed: ' + (errLines || 'source.mp4 was not created. Check cookies or URL.'));
}

const resMatch = stdout.match(/RESOLUTION=(\d+)x(\d+)/);
const width = resMatch ? parseInt(resMatch[1], 10) : 1080;
const height = resMatch ? parseInt(resMatch[2], 10) : 1920;
const durMatch = stdout.match(/DURATION=([\d.]+)/);
const duration = durMatch ? parseFloat(durMatch[1]) : 60;
const ar = width / height;
let blurH;
if (ar < 0.7) blurH = Math.round(height * 0.22);
else if (ar > 1.2) blurH = Math.round(height * 0.18);
else blurH = Math.round(height * 0.2);
const blurY = height - blurH;

return [{
  json: {
    job_id: config.job_id,
    work_dir: config.work_dir,
    url: config.url,
    source_url: config.url,
    youtube_url: config.url,
    platform: config.platform,
    lang: config.lang,
    lang_name: config.lang_name,
    vo_voice: config.vo_voice,
    vo_rate: config.vo_rate,
    vo_pitch: config.vo_pitch,
    width,
    height,
    duration,
    blur_y: blurY,
    blur_h: blurH,
    updated_at: new Date().toISOString()
  }
}];

const stdout = $input.first().json.stdout || '';

const startMarker = '=== TRANSCRIPT_START ===';
const endMarker = '=== TRANSCRIPT_END ===';
const startIdx = stdout.indexOf(startMarker);
const endIdx = stdout.indexOf(endMarker);

let srtRaw = '';
if (startIdx !== -1 && endIdx !== -1) {
  srtRaw = stdout.substring(startIdx + startMarker.length, endIdx).trim();
}

if (!srtRaw || srtRaw.length < 5) {
  const detected = stdout.match(/Detected language: (\w+)/);
  const lang = detected ? detected[1] : 'unknown';
  throw new Error(
    'ဘီဒီယိုထဲမှာ စကားပြောသံ မတွေ့ရပါ (Detected: ' + lang + ')။ ' +
    'စကားပြောပါတဲ့ ဗီဒီယို ထပ်ပို့ကြည့်ပါ။'
  );
}

// Parse SRT into structured blocks
const blocks = srtRaw.split(/\n\n+/).filter(b => b.trim());
const timestamps = [];
const texts = [];

for (const block of blocks) {
  const lines = block.trim().split('\n');
  if (lines.length < 2) continue;

  let tsLine = -1;
  let idLine = -1;
  for (let i = 0; i < lines.length; i++) {
    if (/^\d+$/.test(lines[i].trim())) idLine = i;
    if (/\d{2}:\d{2}:\d{2}[,.]\d{3}\s*-->\s*\d{2}:\d{2}:\d{2}[,.]\d{3}/.test(lines[i])) {
      tsLine = i;
      break;
    }
  }
  if (tsLine < 0) continue;

  const id = idLine >= 0 ? lines[idLine].trim() : String(timestamps.length + 1);
  const ts = lines[tsLine].trim();
  const text = lines.slice(tsLine + 1).join(' ').replace(/<[^>]+>/g, '').trim();

  if (!text) continue;

  timestamps.push({ id, ts });
  texts.push(text);
}

if (texts.length === 0) {
  throw new Error('SRT parsing failed: no subtitle blocks found');
}

return [{
  json: {
    timestamps,
    texts,
    block_count: texts.length,
    texts_json: JSON.stringify(texts),
    transcript: srtRaw
  }
}];

const geminiOut = $input.first().json;
const parseOut = $('Parse Transcript').first().json;
const info = $('Parse Video Info').first().json;

let rawText = '';
if (typeof geminiOut.text === 'string') rawText = geminiOut.text.trim();
else if (geminiOut.content?.parts?.[0]?.text) rawText = geminiOut.content.parts[0].text.trim();
else if (geminiOut.candidates?.[0]?.content?.parts?.[0]?.text) rawText = geminiOut.candidates[0].content.parts[0].text.trim();
else rawText = JSON.stringify(geminiOut);
if (geminiOut.error) {
  throw new Error('Gemini error: ' + JSON.stringify(geminiOut.error).substring(0, 300));
}
rawText = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let translatedTexts;
let seo = {};
try {
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON object found');
  const parsed = JSON.parse(jsonMatch[0]);
  translatedTexts = parsed.translated_texts;
  seo = parsed.seo || {};
  if (!Array.isArray(translatedTexts)) throw new Error('translated_texts is not an array');
} catch (e) {
  try {
    const arrMatch = rawText.match(/\[[\s\S]*\]/);
    if (!arrMatch) throw new Error('No parseable response');
    translatedTexts = JSON.parse(arrMatch[0]);
  } catch (e2) {
    throw new Error('Failed to parse Gemini response: ' + e.message + ' | Raw: ' + rawText.substring(0, 300));
  }
}

const timestamps = parseOut.timestamps || [];
const originals = parseOut.texts || [];
if (translatedTexts.length !== timestamps.length) {
  if (translatedTexts.length < timestamps.length) {
    for (let i = translatedTexts.length; i < timestamps.length; i++) translatedTexts.push(originals[i] || '...');
  } else {
    translatedTexts = translatedTexts.slice(0, timestamps.length);
  }
}

const cleanedTexts = translatedTexts.map((text, index) => {
  const original = originals[index] || '';
  const normalized = String(text || '').replace(/\s+/g, ' ').trim();
  return normalized || original || '...';
});

const srtLines = [];
for (let i = 0; i < timestamps.length; i++) {
  srtLines.push(timestamps[i].id);
  srtLines.push(timestamps[i].ts);
  srtLines.push(cleanedTexts[i]);
  srtLines.push('');
}
const burmeseSrt = srtLines.join('\n');
const srtB64 = Buffer.from(burmeseSrt, 'utf-8').toString('base64');

return [{
  json: {
    job_id: info.job_id,
    work_dir: info.work_dir,
    width: info.width,
    height: info.height,
    duration: info.duration,
    platform: info.platform,
    source_url: info.source_url || info.url,
    lang: info.lang,
    lang_name: info.lang_name,
    vo_voice: info.vo_voice,
    vo_rate: info.vo_rate,
    vo_pitch: info.vo_pitch,
    burmese_srt_b64: srtB64,
    translated_texts: cleanedTexts,
    original_texts: originals,
    timestamps,
    block_count: timestamps.length,
    srt_preview: burmeseSrt.substring(0, 300),
    seo
  }
}];

const item = $input.first();
const hasBinary = !!item.binary?.data;
if (hasBinary) {
  return [{ json: { success: true, stage: 'rendering', error_message: null }, binary: item.binary }];
}

try {
  const parseOut = $('Parse Transcript').first().json || {};
  if (parseOut.error) {
    return [{ json: { success: false, stage: 'transcribe_failed', error_message: String(parseOut.error).slice(0, 1000) } }];
  }
} catch (error) {}

try {
  const buildOut = $('Build FFmpeg Plan').first().json || {};
  if (buildOut.error) {
    return [{ json: { success: false, stage: 'translate_failed', error_message: String(buildOut.error).slice(0, 1000) } }];
  }
} catch (error) {}

try {
  const voOut = $('Generate Voiceover').first().json || {};
  const text = `${voOut.stdout || ''} ${voOut.stderr || ''}`;
  if (/ERROR|failed|exception/i.test(text)) {
    return [{ json: { success: false, stage: 'tts_failed', error_message: text.split('\n').filter((line) => /ERROR|failed|exception/i.test(line)).join(' | ').slice(0, 1000) || text.slice(0, 1000) } }];
  }
} catch (error) {}

try {
  const mixOut = $('Mix VO + Render Final').first().json || {};
  const text = `${mixOut.stdout || ''} ${mixOut.stderr || ''}`;
  if (/ERROR|failed|exception/i.test(text)) {
    return [{ json: { success: false, stage: 'render_failed', error_message: text.split('\n').filter((line) => /ERROR|failed|exception/i.test(line)).join(' | ').slice(0, 1000) || text.slice(0, 1000) } }];
  }
} catch (error) {}

try {
  const dlOut = $('Download Video').first().json.stdout || '';
  if (/ERROR: source\.mp4 not found|Unsupported platform|yt-dlp binary not available/i.test(dlOut)) {
    return [{ json: { success: false, stage: 'download_failed', error_message: dlOut.split('\n').filter((line) => /ERROR/i.test(line)).join(' | ').slice(0, 1000) || dlOut.slice(0, 1000) } }];
  }
} catch (error) {}

return [{ json: { success: false, stage: 'render_failed', error_message: 'ဗီဒီယို ဖိုင် ရရှိ၍ မရပါ' } }];

