const stdout = $input.first().json.stdout || '';
if (!stdout.includes('BLUR_READY=true')) {
  return [{ json: { skip: true } }];
}

const get = (key) => {
  const match = stdout.match(new RegExp(`${key}=(.+)`));
  return match ? match[1].trim() : '';
};

const plan = $('Build FFmpeg Plan').first().json;

return [{
  json: {
    skip: false,
    wd: plan.work_dir,
    width: parseInt(get('WIDTH'), 10) || 0,
    height: parseInt(get('HEIGHT'), 10) || 0,
    frame_path: get('FRAME')
  }
}];

