const item = $input.first();
const safeId = String(($('Video Serve Webhook').first().json.query?.job_id || '')).replace(/[^A-Za-z0-9_-]/g, '');
if (item.binary?.data) {
  return [{ json: { success: true, job_id: safeId }, binary: item.binary }];
}
return [{ json: { success: false, job_id: safeId, status: 'failed', stage: 'done', error_message: 'Final video not found', updated_at: new Date().toISOString() } }];

const blurStdout = String(($('Apply Caption Blur').first().json.stdout || ''));
const blurFailed = /BLUR_FAILED=true|BLUR_SKIPPED=true/.test(blurStdout);
const results = [];

const inspect = (name, service) => {
  try {
    const item = $(name).first();
    const text = JSON.stringify(item.json || {});
    const failed = !!item.json?.error || /ERROR|failed|invalid|unauthorized/i.test(text + ' ' + (item.json?.stdout || ''));
    results.push({ service, failed, detail: failed ? text.slice(0, 800) : '' });
  } catch (error) {
    results.push({ service, failed: true, detail: String(error).slice(0, 800) });
  }
};
inspect('TikTok Publish', 'tiktok');
inspect('Upload a video', 'youtube');
inspect('Facebook Graph API', 'facebook');

const failures = results.filter((item) => item.failed);
let stage = 'done';
let errorMessage = null;
if (failures.length > 0) {
  stage = 'publish_failed';
  errorMessage = failures.map((item) => `${item.service}: ${item.detail}`).join(' | ').slice(0, 1500);
} else if (blurFailed) {
  stage = 'blur_failed';
  errorMessage = 'Caption blur skipped; keeping unblurred final video';
}

return [{
  json: {
    job_id: $('Validate URL').first().json.job_id,
    stage,
    status: 'done',
    error_message: errorMessage,
    publish_results: results,
    blur_failed: blurFailed,
    updated_at: new Date().toISOString(),
  }
}];
